  gift_friendly = EXCLUDED.gift_friendly,
  buyer_mode_label = EXCLUDED.buyer_mode_label,
  gift_note = EXCLUDED.gift_note,
  ownership_note = EXCLUDED.ownership_note,
  product_family_label = EXCLUDED.product_family_label,
  primary_persona = EXCLUDED.primary_persona,
  card_cta_label = EXCLUDED.card_cta_label,
  render_rule = EXCLUDED.render_rule,
  is_active = true,
  updated_at = now();

UPDATE public.pl_age_band_category_type_products p
SET
  is_active = false,
  updated_at = now()
WHERE p.age_band_id IN (SELECT DISTINCT age_band_id FROM tmp_discover_projection_stage);

DO $$
DECLARE
  v_rows_loaded INTEGER;
  v_rows_4_6m INTEGER;
  v_clusters_4_6m INTEGER;
  v_rows_6_9m INTEGER;
  v_clusters_6_9m INTEGER;
  v_rows_9_12m INTEGER;
  v_clusters_9_12m INTEGER;
  v_stage3_active INTEGER;
BEGIN
  SELECT COUNT(*) INTO v_rows_loaded FROM tmp_discover_projection_stage;
  SELECT COUNT(*) INTO v_rows_4_6m FROM tmp_discover_projection_stage WHERE age_band_id = '4-6m';
  SELECT COUNT(DISTINCT stage1_wrapper_ux_slug) INTO v_clusters_4_6m
  FROM tmp_discover_projection_stage WHERE age_band_id = '4-6m';
  SELECT COUNT(*) INTO v_rows_6_9m FROM tmp_discover_projection_stage WHERE age_band_id = '6-9m';
  SELECT COUNT(DISTINCT stage1_wrapper_ux_slug) INTO v_clusters_6_9m
  FROM tmp_discover_projection_stage WHERE age_band_id = '6-9m';
  SELECT COUNT(*) INTO v_rows_9_12m FROM tmp_discover_projection_stage WHERE age_band_id = '9-12m';
  SELECT COUNT(DISTINCT stage1_wrapper_ux_slug) INTO v_clusters_9_12m
  FROM tmp_discover_projection_stage WHERE age_band_id = '9-12m';
  SELECT COUNT(*) INTO v_stage3_active
  FROM public.pl_age_band_category_type_products
  WHERE age_band_id IN ('4-6m', '6-9m', '9-12m')
    AND is_active = true;

  RAISE NOTICE 'Discover projection rows loaded: % (expected 147)', v_rows_loaded;
  RAISE NOTICE '4-6m rows: % (expected 45), clusters: % (expected 8)', v_rows_4_6m, v_clusters_4_6m;
  RAISE NOTICE '6-9m rows: % (expected 42), clusters: % (expected 8)', v_rows_6_9m, v_clusters_6_9m;
  RAISE NOTICE '9-12m rows: % (expected 60), clusters: % (expected 8)', v_rows_9_12m, v_clusters_9_12m;
  RAISE NOTICE 'Active Stage 3 mappings (expected 0): %', v_stage3_active;

  IF v_rows_loaded <> 147 THEN
    RAISE EXCEPTION 'Row count validation failed';
  END IF;
  IF v_rows_4_6m <> 45 THEN
    RAISE EXCEPTION 'Row count validation failed for 4-6m';
  END IF;
  IF v_rows_6_9m <> 42 THEN
    RAISE EXCEPTION 'Row count validation failed for 6-9m';
  END IF;
  IF v_rows_9_12m <> 60 THEN
    RAISE EXCEPTION 'Row count validation failed for 9-12m';
  END IF;
  IF v_clusters_4_6m <> 8 THEN
    RAISE EXCEPTION 'Cluster count validation failed for 4-6m';
  END IF;
  IF v_clusters_6_9m <> 8 THEN
    RAISE EXCEPTION 'Cluster count validation failed for 6-9m';
  END IF;
  IF v_clusters_9_12m <> 8 THEN
    RAISE EXCEPTION 'Cluster count validation failed for 9-12m';
  END IF;
END $$;

COMMIT;

